import{E as e,R as t,U as n,_ as r,et as i,f as a,h as o,pt as s,v as c,x as l,y as u,z as d}from"./runtime-core.esm-bundler-ChtuvW5g.js";var f={class:`ant-doc vp-doc`},p=l({__name:`index.en-US`,setup(l,{expose:p}){let m={title:`ProLayout`,frontmatter:{category:`Components`,group:`Layout`,title:`ProLayout`,cover:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`,coverDark:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`},headers:[{level:2,title:`When To Use`,slug:`when-to-use`,link:`#when-to-use`,children:[]},{level:2,title:`Examples`,slug:`examples`,link:`#examples`,children:[{level:3,title:`Basic`,slug:`layout-demo-basic`,link:`#layout-demo-basic`,children:[]},{level:3,title:`Help`,slug:`layout-demo-help`,link:`#layout-demo-help`,children:[]}]},{level:2,title:`API`,slug:`api`,link:`#api`,children:[{level:3,title:`ProLayout`,slug:`prolayout`,link:`#prolayout`,children:[]},{level:3,title:`menu`,slug:`menu`,link:`#menu`,children:[]},{level:3,title:`SettingDrawer`,slug:`settingdrawer`,link:`#settingdrawer`,children:[]},{level:3,title:`Events`,slug:`events`,link:`#events`,children:[]},{level:3,title:`Slots`,slug:`slots`,link:`#slots`,children:[]}]},{level:2,title:`Design Token`,slug:`theme-variables`,link:`#theme-variables`,children:[]},{level:2,title:`FAQ`,slug:`faq`,link:`#faq`,children:[{level:3,title:`How to choose a layout mode?`,slug:`layout-mode`,link:`#layout-mode`,children:[]},{level:3,title:`How to hide regions that are not needed?`,slug:`custom-layout`,link:`#custom-layout`,children:[]}]}],description:``},h={category:`Components`,group:`Layout`,title:`ProLayout`,cover:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`,coverDark:`https://gw.alipayobjects.com/zos/antfincdn/4n5H%24UX%24j/bianzu%2525204.svg`},g=s({});d(`__pageData__`,e=>{g.value=e});let _=e(`__pageData__`,null);return _&&_(m),d(`__pageInfo__`,m),p({frontmatter:h,pageData:m}),(e,s)=>{let l=n(`demo`),d=n(`demo-group`),p=n(`ComponentTokenTable`);return t(),o(`div`,f,[s[2]||=r(`<p>ProLayout provides the standard application shell for admin systems: header, side navigation, content area, footer, breadcrumbs, page title, and runtime layout settings. It can generate menus from route data and share layout context with PageContainer, FooterToolbar, and other Pro components.</p><p>ProLayout supports four layout modes: <code>side</code>, <code>top</code>, <code>mix</code>, and <code>left</code>. The <code>left</code> layout keeps the first-level menu in a narrow rail and shows the second-level menu next to it, which is useful for systems with deep navigation and frequent module switching.</p><h2 id="when-to-use" tabindex="-1">When To Use <a class="header-anchor" href="#when-to-use" aria-label="Permalink to &quot;When To Use {#when-to-use}&quot;">​</a></h2><ul><li>When you need a standard admin application shell.</li><li>When menus, breadcrumbs, and page titles should be generated from route data.</li><li>When users need to switch layout mode, theme, fixed header, or fixed sider at runtime.</li><li>When PageContainer should share page title, breadcrumb, content, and footer toolbar context.</li><li>When parts of the layout need to be customized with <code>headerRender</code>, <code>menuRender</code>, <code>menuHeaderRender</code>, or other render hooks.</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples {#examples}&quot;">​</a></h2>`,5),u(d,null,{default:i(()=>[u(l,{src:`/src/pages/components/layout/demo/basic.vue`,iframe:`550`},{default:i(()=>[...s[0]||=[c(`Basic`,-1)]]),_:1}),u(l,{src:`/src/pages/components/layout/demo/help.vue`,iframe:`360`},{default:i(()=>[...s[1]||=[c(`Help`,-1)]]),_:1})]),_:1}),s[3]||=r(`<h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><h3 id="prolayout" tabindex="-1">ProLayout <a class="header-anchor" href="#prolayout" aria-label="Permalink to &quot;ProLayout {#prolayout}&quot;">​</a></h3><blockquote><p>All props ending with <code>Render</code> can be set to <code>false</code> to skip rendering that region. They can also be customized through slots with the same names.</p></blockquote><table class="component-table-api"><thead><tr><th>Property</th><th>Description</th><th>Type</th><th>Default</th><th>Version</th></tr></thead><tbody><tr><td>title</td><td>Layout title, used by the menu header and document title</td><td><code>string | false</code></td><td><code>Antdv Next Pro</code></td><td>-</td></tr><tr><td>logo</td><td>Logo in the menu header. Supports image URL, VNode, render function, or <code>false</code></td><td><code>VueNode | false</code></td><td>Built-in Logo</td><td>-</td></tr><tr><td>layout</td><td>Layout mode</td><td><code>&#39;side&#39; | &#39;top&#39; | &#39;mix&#39; | &#39;left&#39;</code></td><td><code>&#39;side&#39;</code></td><td>-</td></tr><tr><td>navTheme</td><td>Navigation theme</td><td><code>&#39;light&#39; | &#39;dark&#39; | &#39;realDark&#39;</code></td><td><code>&#39;dark&#39;</code></td><td>-</td></tr><tr><td>contentWidth</td><td>Content width, only works with <code>layout=&quot;top&quot;</code></td><td><code>&#39;Fluid&#39; | &#39;Fixed&#39;</code></td><td><code>&#39;Fluid&#39;</code></td><td>-</td></tr><tr><td>compact</td><td>Whether to enable compact layout</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>fixedHeader</td><td>Whether to fix the header</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>fixedSiderbar</td><td>Whether to fix the sider</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>splitMenus</td><td>Whether to split first-level and child menus, mainly for <code>mix</code> layout</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>suppressSiderWhenMenuEmpty</td><td>Whether to hide the sider when menu data is empty</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>siderWidth</td><td>Width of the side menu</td><td><code>number</code></td><td><code>256</code></td><td>-</td></tr><tr><td>collapsedWidth</td><td>Width of the collapsed side menu</td><td><code>number</code></td><td><code>64</code></td><td>-</td></tr><tr><td>collapsed</td><td>Controlled collapsed state of the side menu</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>defaultCollapsed</td><td>Default collapsed state</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>fixedHeaderSiderWidth</td><td>Sider offset used when calculating fixed Header width. Usually computed internally by <code>left</code> layout</td><td><code>number</code></td><td>-</td><td>-</td></tr><tr><td>breakpoint</td><td>Responsive collapse breakpoint. Set to <code>false</code> to disable it</td><td><code>Breakpoint | false</code></td><td><code>&#39;lg&#39;</code></td><td>-</td></tr><tr><td>disableMobile</td><td>Disable mobile responsive mode</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>pure</td><td>Pure mode. Provides context without rendering the layout shell</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>loading</td><td>Layout loading state. When enabled, only the loading view is rendered</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>location</td><td>Manually specify current route location. Usually unnecessary because ProLayout reads <code>$route</code> from the Vue app instance; pass it manually when no router plugin is installed</td><td><code>RouterTypes[&#39;location&#39;]</code></td><td><code>$route</code> or <code>/</code></td><td>-</td></tr><tr><td>route</td><td>Route config. <code>children</code> is used as default menu data</td><td><code>RouterTypes[&#39;route&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>menu</td><td>Menu behavior config</td><td><code>MenuConfig</code></td><td>-</td><td>-</td></tr><tr><td>menuData</td><td>Menu data passed directly. In Vue apps, load menus and register routes in router guards or stores before passing data to ProLayout</td><td><code>MenuDataItem[]</code></td><td>-</td><td>-</td></tr><tr><td>menuProps</td><td>Props passed to <code>Menu</code>. See antdv-next Menu</td><td><code>MenuProps</code></td><td>-</td><td>-</td></tr><tr><td>mode</td><td>Menu mode, usually controlled by the layout internally</td><td><code>MenuProps[&#39;mode&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>selectedKeys</td><td>Controlled selected menu keys</td><td><code>string[]</code></td><td>-</td><td>-</td></tr><tr><td>openKeys</td><td>Controlled open menu keys. Set to <code>false</code> to disable open-key control</td><td><code>string[] | false</code></td><td>-</td><td>-</td></tr><tr><td>menuDataRender</td><td>Transform menu data before rendering</td><td><code>(menuData: MenuDataItem[]) =&gt; MenuDataItem[]</code></td><td>-</td><td>-</td></tr><tr><td>postMenuData</td><td>Final menu data transform before rendering. It skips later i18n and path processing</td><td><code>(menuData?: MenuDataItem[]) =&gt; MenuDataItem[]</code></td><td>-</td><td>-</td></tr><tr><td>formatMessage</td><td>Menu i18n formatter</td><td><code>(message: MessageDescriptor) =&gt; string | undefined</code></td><td>-</td><td>-</td></tr><tr><td>breadcrumbRender</td><td>Customize breadcrumb data. Return <code>false</code> to hide breadcrumbs</td><td><code>(routes: BreadcrumbProps[&#39;items&#39;]) =&gt; BreadcrumbProps[&#39;items&#39;] | false</code></td><td>-</td><td>-</td></tr><tr><td>breadcrumbProps</td><td>Breadcrumb props passed to PageHeader</td><td><code>BreadcrumbProps &amp; LayoutBreadcrumbProps</code></td><td>-</td><td>-</td></tr><tr><td>itemRender</td><td>Custom breadcrumb item rendering</td><td><code>BreadcrumbProps[&#39;itemRender&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>pageTitleRender</td><td>Customize page title</td><td><code>(options) =&gt; string | undefined | false</code></td><td>-</td><td>-</td></tr><tr><td>contentStyle</td><td>Content area style</td><td><code>CSSProperties</code></td><td>-</td><td>-</td></tr><tr><td>bgLayoutImgList</td><td>Background image list for the layout</td><td><code>BgLayoutImg[]</code></td><td>-</td><td>-</td></tr><tr><td>colorPrimary</td><td>Primary color</td><td><code>string</code></td><td><code>#1677FF</code></td><td>-</td></tr><tr><td>colorWeak</td><td>Whether to enable color-weak mode</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>iconfontUrl</td><td>Custom iconfont Symbol script URL</td><td><code>string</code></td><td>-</td><td>-</td></tr><tr><td>iconPrefixes</td><td>Iconfont prefix for string menu icons</td><td><code>string</code></td><td><code>&#39;icon-&#39;</code></td><td>-</td></tr><tr><td>token</td><td>Component-level design token for Layout</td><td><code>ProTokenType[&#39;layout&#39;]</code></td><td>-</td><td>-</td></tr><tr><td>stylish</td><td>Custom style generators for Header and Sider</td><td><code>{ header?: GenerateStyle; sider?: GenerateStyle }</code></td><td>-</td><td>-</td></tr><tr><td>avatarProps</td><td>Avatar config</td><td><code>AvatarPropsType</code></td><td>-</td><td>-</td></tr><tr><td>appList</td><td>Cross-site app list</td><td><code>AppListProps</code></td><td>-</td><td>-</td></tr><tr><td>itemClick</td><td>Callback when an app-list item is clicked. When provided, automatic navigation is skipped</td><td><code>(item: AppItemProps, popoverRef: ShallowRef) =&gt; void</code></td><td>-</td><td>-</td></tr><tr><td>links</td><td>Shortcut links in the side menu footer</td><td><code>VueNode[] | LinkItem[] | false</code></td><td>-</td><td>-</td></tr><tr><td>siderProps</td><td>Props passed to <code>LayoutSider</code></td><td><code>SiderProps</code></td><td>-</td><td>-</td></tr><tr><td>logoStyle</td><td>Style of the menu logo area</td><td><code>CSSProperties</code></td><td>-</td><td>-</td></tr><tr><td>waterMarkProps</td><td>Watermark config</td><td><code>WatermarkProps</code></td><td>-</td><td>-</td></tr><tr><td>errorBoundaryRender</td><td>Custom error boundary</td><td><code>ErrorBoundaryRender | false</code></td><td>-</td><td>-</td></tr><tr><td>tagsViewRender</td><td>Custom tabs view area</td><td><code>TagsViewRender | false</code></td><td>-</td><td>-</td></tr><tr><td>siderMenuType</td><td>Side menu aggregation mode, shorthand for <code>menu.type</code></td><td><code>&#39;sub&#39; | &#39;group&#39;</code></td><td><code>&#39;sub&#39;</code></td><td>-</td></tr><tr><td>isChildrenLayout</td><td>Whether to render as a child layout</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>headerRender</td><td>Customize Header. Set to <code>false</code> to hide Header</td><td><code>HeaderRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuRender</td><td>Customize menu region. Set to <code>false</code> to hide menu</td><td><code>MenuRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuHeaderRender</td><td>Customize menu logo and title. Set to <code>false</code> to hide it</td><td><code>MenuHeaderRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuItemRender</td><td>Custom leaf menu item rendering</td><td><code>MenuItemRender | false</code></td><td>-</td><td>-</td></tr><tr><td>subMenuItemRender</td><td>Custom parent menu item rendering</td><td><code>SubMenuItemRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuContentRender</td><td>Customize menu content</td><td><code>MenuContentRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuExtraRender</td><td>Extra region below menu header</td><td><code>MenuExtraRender | false</code></td><td>-</td><td>-</td></tr><tr><td>menuFooterRender</td><td>Custom menu footer</td><td><code>MenuFooterRender | false</code></td><td>-</td><td>-</td></tr><tr><td>collapsedButtonRender</td><td>Custom collapsed button. Set to <code>false</code> to hide it</td><td><code>CollapsedButtonRender | false</code></td><td>-</td><td>-</td></tr><tr><td>actionsRender</td><td>Custom action area in Header or Sider</td><td><code>ActionsRender | false</code></td><td>-</td><td>-</td></tr><tr><td>appListRender</td><td>Custom cross-site app list rendering</td><td><code>AppListRender | false</code></td><td>-</td><td>-</td></tr><tr><td>headerTitleRender</td><td>Custom Header title region</td><td><code>HeaderTitleRender | false</code></td><td>-</td><td>-</td></tr><tr><td>headerContentRender</td><td>Custom Header content region</td><td><code>HeaderContentRender | false</code></td><td>-</td><td>-</td></tr><tr><td>footerRender</td><td>Custom footer. Set to <code>false</code> to hide footer</td><td><code>FooterRender | false</code></td><td>-</td><td>-</td></tr><tr><td>pageHeaderRender</td><td>Custom PageHeader rendering for PageContainer</td><td><code>PageHeaderRender | false</code></td><td>-</td><td>-</td></tr><tr><td>footerToolbarContentRender</td><td>Custom FooterToolbar content rendering</td><td><code>FooterToolbarContentRender</code></td><td>-</td><td>-</td></tr></tbody></table><p>In addition to the table above, ProLayout can pass antdv-next Menu props through <code>menuProps</code>; <code>openKeys</code>, <code>openChange</code>, and <code>title</code> are managed by ProLayout itself.</p><h3 id="menu" tabindex="-1">menu <a class="header-anchor" href="#menu" aria-label="Permalink to &quot;menu {#menu}&quot;">​</a></h3><p><code>menu</code> controls open behavior, collapsed behavior, and controlled loading state. For async menus, load data in Vue Router guards or stores; ProLayout only renders prepared <code>route.children</code> or <code>menuData</code>.</p><table class="component-table-api"><thead><tr><th>Property</th><th>Description</th><th>Type</th><th>Default</th><th>Version</th></tr></thead><tbody><tr><td>locale</td><td>Whether to enable menu i18n</td><td><code>boolean</code></td><td><code>true</code></td><td>-</td></tr><tr><td>loading</td><td>Menu loading state</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>defaultOpenAll</td><td>Expand all menu items by default. Only works before layout mount</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>autoClose</td><td>Whether selecting a menu item auto-closes the mobile menu. Set to <code>false</code> to disable it</td><td><code>boolean</code></td><td><code>true</code></td><td>-</td></tr><tr><td>ignoreFlatMenu</td><td>Ignore menu state collapsed manually by users</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>hideMenuWhenCollapsed</td><td>Completely hide menu content when collapsed</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>collapsedShowTitle</td><td>Show title when menu is collapsed</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>type</td><td>Menu aggregation mode</td><td><code>&#39;sub&#39; | &#39;group&#39;</code></td><td>-</td><td>-</td></tr></tbody></table><h3 id="settingdrawer" tabindex="-1">SettingDrawer <a class="header-anchor" href="#settingdrawer" aria-label="Permalink to &quot;SettingDrawer {#settingdrawer}&quot;">​</a></h3><p>SettingDrawer is a visual settings panel for ProLayout. It is useful for demos or systems that allow users to configure layout at runtime.</p><table class="component-table-api"><thead><tr><th>Property</th><th>Description</th><th>Type</th><th>Default</th><th>Version</th></tr></thead><tbody><tr><td>settings</td><td>Current layout settings</td><td><code>Partial&lt;ProSettings&gt;</code></td><td><code>defaultSettings</code></td><td>-</td></tr><tr><td>collapsed</td><td>Whether the settings panel is collapsed</td><td><code>boolean</code></td><td>-</td><td>-</td></tr><tr><td>colorList</td><td>Theme color candidates. Set to <code>false</code> to hide color selection</td><td><code>{ key: string; color: string; title?: string }[] | false</code></td><td>Built-in palette</td><td>-</td></tr><tr><td>hideHintAlert</td><td>Hide the hint alert</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr><tr><td>hideCopyButton</td><td>Hide the copy settings button</td><td><code>boolean</code></td><td><code>false</code></td><td>-</td></tr></tbody></table><h3 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events {#events}&quot;">​</a></h3><p>Events are registered with Vue event syntax, such as <code>@collapse</code>, <code>@menu-header-click</code>, and <code>@update:collapsed</code>.</p><table class="component-table-api"><thead><tr><th>Event</th><th>Description</th><th>Type</th><th>Version</th></tr></thead><tbody><tr><td>pageChange</td><td>Triggered when page location changes</td><td><code>(location?: RouterTypes[&#39;location&#39;]) =&gt; void</code></td><td>-</td></tr><tr><td>collapse</td><td>Triggered when the side menu collapses or expands</td><td><code>(collapsed: boolean) =&gt; void</code></td><td>-</td></tr><tr><td>openChange</td><td>Triggered when menu open keys change</td><td><code>(openKeys?: Key[] | false) =&gt; void</code></td><td>-</td></tr><tr><td>select</td><td>Triggered when selected menu keys change</td><td><code>(selectedKeys: Key[]) =&gt; void</code></td><td>-</td></tr><tr><td>menuHeaderClick</td><td>Triggered when the menu header is clicked</td><td><code>(e: MouseEvent) =&gt; void</code></td><td>-</td></tr><tr><td>itemClick</td><td>Triggered when an app-list item is clicked</td><td><code>(item: AppItemProps, popoverRef: ShallowRef) =&gt; void</code></td><td>-</td></tr><tr><td>SettingDrawer: settingChange</td><td>Triggered when SettingDrawer settings change</td><td><code>(settings: Partial&lt;ProSettings&gt;) =&gt; void</code></td><td>-</td></tr><tr><td>SettingDrawer: collapse</td><td>Triggered when SettingDrawer collapses or expands</td><td><code>(collapsed: boolean) =&gt; void</code></td><td>-</td></tr><tr><td>SettingDrawer: update:collapsed</td><td><code>v-model:collapsed</code> update event</td><td><code>(collapsed: boolean) =&gt; void</code></td><td>-</td></tr></tbody></table><h3 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to &quot;Slots {#slots}&quot;">​</a></h3><table class="component-table-api"><thead><tr><th>Slot</th><th>Description</th><th>Type</th><th>Version</th></tr></thead><tbody><tr><td>headerRender</td><td>Custom Header rendering</td><td><code>HeaderRender</code></td><td>-</td></tr><tr><td>menuRender</td><td>Custom menu rendering</td><td><code>MenuRender</code></td><td>-</td></tr><tr><td>menuHeaderRender</td><td>Custom menu header rendering</td><td><code>MenuHeaderRender</code></td><td>-</td></tr><tr><td>headerTitleRender</td><td>Custom Header title rendering</td><td><code>HeaderTitleRender</code></td><td>-</td></tr><tr><td>headerContentRender</td><td>Custom Header content rendering</td><td><code>HeaderContentRender</code></td><td>-</td></tr><tr><td>actionsRender</td><td>Custom action area rendering</td><td><code>ActionsRender</code></td><td>-</td></tr><tr><td>footerRender</td><td>Custom footer rendering</td><td><code>FooterRender</code></td><td>-</td></tr><tr><td>tagsViewRender</td><td>Custom tabs view rendering</td><td><code>TagsViewRender</code></td><td>-</td></tr><tr><td>footerToolbarContentRender</td><td>Custom FooterToolbar content rendering</td><td><code>FooterToolbarContentRender</code></td><td>-</td></tr><tr><td>collapsedButtonRender</td><td>Custom collapsed button rendering</td><td><code>CollapsedButtonRender</code></td><td>-</td></tr><tr><td>errorBoundaryRender</td><td>Custom error boundary rendering</td><td><code>ErrorBoundaryRender</code></td><td>-</td></tr><tr><td>appListRender</td><td>Custom app-list rendering</td><td><code>AppListRender</code></td><td>-</td></tr><tr><td>menuItemRender</td><td>Custom leaf menu item rendering</td><td><code>MenuItemRender</code></td><td>-</td></tr><tr><td>subMenuItemRender</td><td>Custom parent menu item rendering</td><td><code>SubMenuItemRender</code></td><td>-</td></tr><tr><td>menuContentRender</td><td>Custom menu content rendering</td><td><code>MenuContentRender</code></td><td>-</td></tr><tr><td>menuFooterRender</td><td>Custom menu footer rendering</td><td><code>MenuFooterRender</code></td><td>-</td></tr><tr><td>menuExtraRender</td><td>Custom extra region below menu header</td><td><code>MenuExtraRender</code></td><td>-</td></tr><tr><td>pageHeaderRender</td><td>Custom PageHeader rendering for PageContainer</td><td><code>PageHeaderRender</code></td><td>-</td></tr></tbody></table><h2 id="theme-variables" tabindex="-1">Design Token <a class="header-anchor" href="#theme-variables" aria-label="Permalink to &quot;Design Token {#theme-variables}&quot;">​</a></h2><p>Design Token is the basic element of the design system. You can customize Header, Sider, content, and menu colors through the <code>token</code> prop or ProConfigProvider.</p>`,18),a(`p`,null,[u(p,{component:`ProLayout`})]),s[4]||=r(`<h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ {#faq}&quot;">​</a></h2><h3 id="layout-mode" tabindex="-1">How to choose a layout mode? <a class="header-anchor" href="#layout-mode" aria-label="Permalink to &quot;How to choose a layout mode? {#layout-mode}&quot;">​</a></h3><ul><li><code>side</code>: the most common side navigation layout for admin systems.</li><li><code>top</code>: top navigation layout for a small number of navigation items and centered content.</li><li><code>mix</code>: first-level navigation in the header with child menus in the sider.</li><li><code>left</code>: first-level menu fixed in the left rail with the second-level menu expanded beside it.</li></ul><h3 id="custom-layout" tabindex="-1">How to hide regions that are not needed? <a class="header-anchor" href="#custom-layout" aria-label="Permalink to &quot;How to hide regions that are not needed? {#custom-layout}&quot;">​</a></h3><p>ProLayout provides a group of <code>xxxRender</code> APIs for controlling layout regions. Pass a function to customize rendering, or pass <code>false</code> to hide the region.</p><ul><li><code>headerRender</code> customizes or hides the header.</li><li><code>footerRender</code> customizes or hides the footer.</li><li><code>menuRender</code> customizes or hides the menu region.</li><li><code>menuHeaderRender</code> customizes or hides the menu header.</li><li><code>menuExtraRender</code> adds extra content between the menu header and menu list.</li><li><code>collapsedButtonRender</code> customizes or hides the menu collapse button.</li></ul><p><img src="https://gw.alipayobjects.com/zos/antfincdn/mCXDkK2pJ0/60298863-F5A5-4af2-923A-13EF912DB0E1.png" alt="setting-drawer-render"></p>`,7)])}}});export{p as default};